function useI18n() {
  const { locale, setLocale } = useI18nContext();

  const t = translations[locale];

  const changeLocale = (newLocale: Locale) => {
    setLocale(newLocale);
    setLocaleInCookie(newLocale);
  };

  // Initialize locale on mount
  useEffect(() => {
    const saved = getLocaleFromCookie() as Locale | null;
    if (!saved) {
      const detected = detectLocale();
      setLocale(detected);
      setLocaleInCookie(detected);
    }
  }, [setLocale]);

  return {
    locale,
    t,
    changeLocale,
  };
}

frontend.src.core.i18n.index.detectLocal.source_code:
function detectLocale(): Locale {
  if (typeof window === "undefined") {
    return "en-US";
  }

  const browserLang =
    navigator.language ||
    (navigator as unknown as { userLanguage: string }).userLanguage;

  // Check if browser language is Chinese (zh, zh-CN, zh-TW, etc.)
  if (browserLang.toLowerCase().startsWith("zh")) {
    return "zh-CN";
  }

  return "en-US";
}

