function getFileIcon(filepath: string, className?: string) {
  const extension = getFileExtension(filepath);
  const { isCodeFile } = checkCodeFile(filepath);
  switch (extension) {
    case "skill":
      return <FileCogIcon className={className} />;
    case "html":
      return <CompassIcon className={className} />;
    case "txt":
    case "md":
      return <BookOpenTextIcon className={className} />;
    case "jpg":
    case "jpeg":
    case "png":
    case "gif":
    case "bmp":
    case "tiff":
    case "ico":
    case "webp":
    case "svg":
    case "heic":
      return <ImageIcon className={className} />;
    case "mp3":
    case "wav":
    case "ogg":
    case "aac":
    case "m4a":
    case "flac":
    case "wma":
    case "aiff":
    case "ape":
    case "mp4":
    case "mov":
    case "m4v":
      return <FilePlayIcon className={className} />;
    default:
      if (isCodeFile) {
        return <FileCodeIcon className={className} />;
      }
      return <FileTextIcon className={className} />;
  }
}

